-- B-tree index (default) -- best for equality and range queries
CREATE INDEX idx_users_email ON users(email);

-- Composite index -- for queries that filter on multiple columns
CREATE INDEX idx_posts_author_date ON posts(author_id, created_at DESC);

-- Partial index -- only index rows matching a condition (saves space)
CREATE INDEX idx_posts_published ON posts(created_at DESC) WHERE published = TRUE;

-- GIN index -- for full-text search and JSONB columns
CREATE INDEX idx_posts_search ON posts USING GIN(to_tsvector('english', title || ' ' || body));

-- Unique index -- enforces uniqueness at the database level
CREATE UNIQUE INDEX idx_users_username ON users(LOWER(username));

-- EXPLAIN ANALYZE shows how PostgreSQL executes a query
EXPLAIN ANALYZE SELECT * FROM posts WHERE author_id = 5 ORDER BY created_at DESC LIMIT 20;
